class Tally:
    def __init__(self): self.count = 0
    def mark(self): self.count += 1

t = Tally()
for _ in range(2): t.mark()
print(t.count)

class Sensor:
    def __init__(self): self.tripped = False
    def check(self, v): self.tripped = (v > 90)
s = Sensor()
s.check(95)
print(s.tripped)

